// Lookup functions

export function lookupREEL3AgeEquivalent(rawScore: number, domain: 'receptive' | 'expressive'): number | null {
  const entry = REEL3_AGE_EQUIVALENTS.find(e => e.raw === rawScore);
  if (!entry) return null;
  return entry[domain];
}

export function lookupREEL3AbilityScore(rawScore: number, ageMonths: number, domain: 'receptive' | 'expressive'): number | null {
  // Find the correct age group
  const ageKeys = Object.keys(REEL3_ABILITY_SCORES).map(Number).sort((a, b) => a - b);
  let matchKey: number | null = null;

  // Find the largest age key <= ageMonths
  for (const key of ageKeys) {
    if (key <= ageMonths) matchKey = key;
    else break;
  }

  if (matchKey === null) matchKey = ageKeys[0];
  const table = REEL3_ABILITY_SCORES[String(matchKey)];
  if (!table) return null;

  const entry = table.find(e => e.raw === rawScore);
  if (!entry) return null;
  return entry[domain];
}

export function lookupREEL3PercentileRank(abilityScore: number): string | null {
  return REEL3_PERCENTILE_RANKS[abilityScore] ?? null;
}

export function lookupREEL3DescriptiveTerm(abilityScore: number): string {
  let term = 'Very Poor';
  for (const entry of REEL3_DESCRIPTIVE_TERMS) {
    if (abilityScore >= entry.minScore) term = entry.term;
    else break;
  }
  return term;
}

export function lookupREEL3LanguageAbility(sumSubtestScores: number): number | null {
  return REEL3_LANGUAGE_ABILITY[sumSubtestScores] ?? null;
}
